import os
from subprocess import call

def process_image(event, context):
    # Extract file name and conversion options from event metadata
    file_name = event['name']
    conversion_options = event.get('conversionOptions', '')

    # Define the source and destination paths for the image
    source_path = f'/tmp/{file_name}'
    destination_path = f'/tmp/converted_{file_name}'

    # Download the file from Cloud Storage to a local path
    with open(source_path, 'wb') as f:
        f.write(event['data'])

    # Construct the convert command using ImageMagick
    convert_command = ['convert', source_path] + conversion_options.split() + [destination_path]

    # Run the convert command
    call(convert_command)

